def flat():
    """Splaszczony slownik {key: {pl,uk,ru,en}} do translations.js."""
    d = dict(UI)
    for slug, c in CAT.items():
        for f in ("name", "tag", "lead", "intro"):
            d[f"cat_{slug}_{f}"] = c[f]
    for slug, mm in MASTER.items():
        d[f"role_{slug}"] = mm["role"]
        for i, p in enumerate(mm["bio"]):
            d[f"bio_{slug}_{i}"] = p
    for i, rv in enumerate(REVIEWS):
        d[f"rev{i}_text"] = rv["text"]
        d[f"rev{i}_svc"] = rv["svc"]
    return d
